import { JsonRpcProvider, Network } from "ethers";
var providerCache = /* @__PURE__ */ new Map();
function getProvider(config2) {
  const cacheKey = `${config2.chainId}:${config2.rpcUrl}`;
  const cached = providerCache.get(cacheKey);
  if (cached) return cached;
  const network = new Network(config2.name, config2.chainId);
  const provider = new JsonRpcProvider(config2.rpcUrl, network, {
    batchMaxCount: 1,
    // No batching — prevents one failed call from poisoning others
    staticNetwork: network,
    // Prevents _detectNetwork which redirects to built-in Infura endpoints
    pollingInterval: 3e4
    // 30s polling to avoid rate limits on free RPCs
  });
  providerCache.set(cacheKey, provider);
  return provider;
}
function clearProviderCache() {
  providerCache.clear();
}

